package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.InputStream;
import java.io.InputStreamReader;
import java.net.URL;
import java.nio.charset.Charset;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class CSVParserTest {

    private URL mockUrl;
    private InputStream mockInputStream;
    private Charset charset;
    private CSVFormat format;

    @BeforeEach
    void setUp() throws IOException {
        mockUrl = mock(URL.class);
        mockInputStream = mock(InputStream.class);
        charset = Charset.forName("UTF-8");
        format = mock(CSVFormat.class);

        when(mockUrl.openStream()).thenReturn(mockInputStream);
    }

    @Test
    void testParse_NullUrl_ThrowsException() {
        NullPointerException thrown = assertThrows(NullPointerException.class,
                () -> CSVParser.parse(null, charset, format));
        assertEquals("url", thrown.getMessage());
    }

    @Test
    void testParse_NullCharset_ThrowsException() {
        NullPointerException thrown = assertThrows(NullPointerException.class,
                () -> CSVParser.parse(mockUrl, null, format));
        assertEquals("charset", thrown.getMessage());
    }

    @Test
    void testParse_NullFormat_ThrowsException() {
        NullPointerException thrown = assertThrows(NullPointerException.class,
                () -> CSVParser.parse(mockUrl, charset, null));
        assertEquals("format", thrown.getMessage());
    }

    @Test
    void testParse_Success() throws IOException {
        try (MockedStatic<Assertions> assertionsMockedStatic = Mockito.mockStatic(Assertions.class)) {
            // Mock Assertions.notNull to do nothing (no exception)
            assertionsMockedStatic.when(() -> Assertions.notNull(any(), anyString())).thenAnswer(invocation -> null);

            CSVParser parser = CSVParser.parse(mockUrl, charset, format);

            assertNotNull(parser);
            // Since constructor is called, verify that the InputStreamReader was created with the mockInputStream and charset
            // This is implicit by no exceptions thrown and returned object non-null
        }
    }
}
